import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './Dashboard.css';

export default function AdminDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [filterCat, setFilterCat] = useState('all');
  const [filterStatus, setFilterStatus] = useState('all');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    if (!token || user?.role !== 'admin') navigate('/login');
    fetchComplaints();
  }, [filterCat, filterStatus]);

  const fetchComplaints = async () => {
    try {
      const params = new URLSearchParams();
      if (filterCat !== 'all') params.append('category', filterCat);
      if (filterStatus !== 'all') params.append('status', filterStatus);
      const url = `/api/complaints?${params}`;
      const res = await axios.get(url, { headers: { 'x-auth-token': token } });
      setComplaints(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await axios.put(`/api/complaints/${id}`, { status }, { headers: { 'x-auth-token': token } });
      fetchComplaints();
    } catch (err) {
      alert('Failed to update');
    }
  };

  const logout = () => { localStorage.clear(); navigate('/login'); };

  const stats = {
    total: complaints.length,
    pending: complaints.filter(c => c.status === 'pending').length,
    inProgress: complaints.filter(c => c.status === 'in-progress').length,
    resolved: complaints.filter(c => c.status === 'resolved').length
  };

  return (
    <div className="dashboard-container">
      <nav className="dashboard-nav">
        <div className="nav-content">
          <div className="nav-brand"><h1>Hostel<span>Hub</span></h1><p>Admin</p></div>
          <div className="nav-stats">
            <div className="stat-item"><span className="stat-value">{stats.total}</span><span>Total</span></div>
            <div className="stat-item pending"><span className="stat-value">{stats.pending}</span><span>Pending</span></div>
            <div className="stat-item in-progress"><span className="stat-value">{stats.inProgress}</span><span>In Progress</span></div>
            <div className="stat-item resolved"><span className="stat-value">{stats.resolved}</span><span>Resolved</span></div>
          </div>
          <div className="nav-user">
            <span>{user?.name}</span>
            <button onClick={logout} className="logout-btn">Logout</button>
          </div>
        </div>
      </nav>

      <div className="dashboard-content">
        <div className="content-header">
          <h2>All Complaints</h2>
          <div className="filters">
            <select value={filterCat} onChange={e => setFilterCat(e.target.value)}>
              <option value="all">All Categories</option>
              <option value="plumbing">Plumbing</option>
              <option value="electrical">Electrical</option>
              <option value="carpentry">Carpentry</option>
              <option value="cleaning">Cleaning</option>
              <option value="other">Other</option>
            </select>
            <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
              <option value="all">All Status</option>
              <option value="pending">Pending</option>
              <option value="in-progress">In Progress</option>
              <option value="resolved">Resolved</option>
            </select>
            <button onClick={() => { setFilterCat('all'); setFilterStatus('all'); }}>Clear</button>
          </div>
        </div>

        <div className="complaints-table-wrapper">
          <table className="complaints-table">
            <thead>
              <tr><th>ID</th><th>Category</th><th>Description</th><th>Priority</th><th>Status</th><th>Date</th><th>Student</th><th>Actions</th></tr>
            </thead>
            <tbody>
              {complaints.map(c => (
                <tr key={c._id}>
                  <td>#{c._id.toString().slice(-4)}</td>
                  <td>{c.category}</td>
                  <td>{c.description}</td>
                  <td><span className={`priority-badge priority-${c.priority}`}>{c.priority}</span></td>
                  <td><span className={`status-badge status-${c.status.replace('-','')}`}>{c.status}</span></td>
                  <td>{new Date(c.createdAt).toLocaleDateString()}</td>
                  <td>
                    {c.student?.name}<br/>
                    <small>{c.student?.email}</small><br/>
                    <small>Room: {c.student?.roomNumber}</small>
                  </td>
                  <td>
                    {c.status === 'pending' && <button onClick={() => updateStatus(c._id, 'in-progress')}>Start</button>}
                    {c.status === 'in-progress' && <button onClick={() => updateStatus(c._id, 'resolved')}>Resolve</button>}
                    {c.status === 'resolved' && <span>✅</span>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
